fun solve(words: Array<String>): Array<Long> {
    fun lcp(a: String, b: String): Int {
        val minLen = min(a.length, b.length)
        for (i in 0 until minLen) {
            if (a[i] != b[i]) return i
        }
        return minLen
    }

    val n = words.size
    if (n == 0) return arrayOf()
    if (n == 1) return arrayOf(0L)

    val lcpPairs = Array<Int>(n - 1) { i ->
        lcp(words[i], words[i + 1])
    }

    val prefixMax = IntArray(lcpPairs.size)
    var currentMax = 0
    for (i in 0 until lcpPairs.size) {
        currentMax = max(lcpPairs[i], currentMax)
        prefixMax[i] = currentMax
    }

    val suffixMax = IntArray(lcpPairs.size)
    currentMax = 0
    for (i in (lcpPairs.size - 1) downTo 0) {
        currentMax = max(lcpPairs[i], currentMax)
        suffixMax[i] = currentMax
    }

    val answer = Array<Long>(n) { i ->
        var maxOriginal = 0L
        var newLcp = 0L

        val m = lcpPairs.size
        if (m == 0) {
            return 0L
        }

        if (i == 0) {
            if (m >= 2) {
